import numpy as np
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from sklearn.metrics import accuracy_score

class SpamDetectionAPI:
    def __init__(self):
        self.vectorizer = CountVectorizer()
        self.model = LogisticRegression()

    def train(self, emails):
        # Convert the email text to a numerical representation using the vectorizer
        X = self.vectorizer.fit_transform(emails)
        # Train the logistic regression model on the training data
        self.model.fit(X, np.array([1 if label == 'spam' else 0 for label in emails]))

    def predict(self, email):
        # Convert the new email text to a numerical representation using the vectorizer
        X = self.vectorizer.transform([email])
        # Use the trained model to make a prediction on the new data
        return self.model.predict_proba(X)[0][1]